import fs from"fs-extra";import path from"node:path";import{kebabCase}from"change-case";function toRelativePath(t,e){return path.relative(t,e).replace(/\\/g,"/")}function getProjectType(t){return"php"===t?"prisma-php":"caspian"}function getConfigFile(t){return"php"===t?"prisma-php.json":"caspian.config.json"}function getExtension(t){return"php"===t?".php":".py"}function getUsage(t,e,n){const o=toRelativePath(t,e);if("php"===n){return{componentType:"class",entryStyle:"namespace",entry:path.relative(path.join(t,"src"),e).split(path.sep).join("\\"),filePattern:`${o}/<ComponentName>.php`,syntax:"jsx-like component tags"}}return{componentType:"function",entryStyle:"module",entry:o.split("/").join("."),filePattern:`${o}/<ComponentName>.py`,syntax:"jsx-like component tags"}}function getCommands(){return{addOne:"npx ppicons add <icon-name>",addMany:"npx ppicons add <icon-a> <icon-b>",addAll:"npx ppicons add --all",updateInstalled:"npx ppicons update"}}function getCatalogApi(){return{listAll:{method:"GET",url:"https://ppicons.tsnc.tech/icons?icon=all",returns:"IconRecord[]",purpose:"List all available icons that can be installed."},getOne:{method:"GET",urlTemplate:"https://ppicons.tsnc.tech/icons?icon=<icon-name>",exampleUrl:"https://ppicons.tsnc.tech/icons?icon=search",returns:"IconRecord",purpose:"Fetch one icon by name before installing it."},responseFields:{id:"number",name:"string",componentName:"string",svg:"string",createdAt:"number",updatedAt:"number"}}}async function collectInstalledIcons(t,e,n){if(!await fs.pathExists(e))return[];const o=getExtension(n);return(await fs.readdir(e)).filter(t=>t.endsWith(o)).sort((t,e)=>t.localeCompare(e)).map(n=>{const a=path.basename(n,o);return{name:kebabCase(a),componentName:a,file:toRelativePath(t,path.join(e,n))}})}export async function writePPIconsManifest({projectRoot:t,targetDir:e,language:n,detectedBy:o}){const a=path.join(t,"ppicons.json"),i=await buildPPIconsManifest({projectRoot:t,targetDir:e,language:n,detectedBy:o});return await fs.writeJson(a,i,{spaces:2}),a}export async function buildPPIconsManifest({projectRoot:t,targetDir:e,language:n,detectedBy:o}){const a=await collectInstalledIcons(t,e,n),i=toRelativePath(t,e),s=getProjectType(n);return{schemaVersion:5,generatedAt:(new Date).toISOString(),project:{type:s,framework:s,language:n,detectedBy:o,rootDirectory:".",sourceDirectory:"src",configFile:getConfigFile(n),manifestFile:"ppicons.json",componentsDirectory:i,iconsDirectory:i,copilotInstructionsFile:".github/copilot-instructions.md",agentsFile:"AGENTS.md"},commands:getCommands(),catalogApi:getCatalogApi(),icons:a,usage:getUsage(t,e,n)}}